// The CONDITION → TRAINING-CONSIDERATION dataset, loaded onto the curated-dataset
// framework (issue #666). Copies the food-drug-interactions.ts shape: import the envelope
// JSON (generated by scripts/gen-condition-training-considerations.ts), validate it once
// with loadDataset(), and expose the consideration ENTRIES the matcher consumes. Identity
// is the stable slug `key` (fieldStrategy) — one entry per key, so the harness's
// identity-resolves / refusal-gate hold. The registry lists this for the linter;
// lib/condition-training-considerations.ts is the DOMAIN matcher (it resolves a live
// condition to entries by normalized name/synonym or ICD-10 code prefix, a many-to-one
// lookup that is domain logic, not the entry identity). Pure — no DB, no network.

import rawConsiderations from "./data/condition-training-considerations.json";
import { loadDataset } from "./loader";
import { fieldStrategy } from "./matcher";
import type { ConditionConsiderationEntry } from "@/scripts/gen-condition-training-considerations";

export type { ConditionConsiderationEntry } from "@/scripts/gen-condition-training-considerations";

// The validated dataset (envelope + guarantees). Throws at module load if the committed
// JSON ever violates the contract — a loud, early failure.
export const conditionTrainingConsiderationsDataset =
  loadDataset<ConditionConsiderationEntry>(rawConsiderations);

// Identity strategy: the stable slug `key` (case-folded). For the linter/harness — each
// entry carries a unique key, so identity resolves and an unknown key refuses (null).
export const conditionConsiderationKeyStrategy = fieldStrategy("key");

// The consideration entries the domain matcher consumes, in curated (source) order.
export const CONDITION_TRAINING_CONSIDERATIONS: ConditionConsiderationEntry[] =
  conditionTrainingConsiderationsDataset.entries;
